import axios from 'axios';

const API_BASE_URL = 'http://localhost:5001'; 

class UserService {
    // Lấy toàn bộ danh sách người dùng
    async getAllUsers() {
        const token = localStorage.getItem("token");
        const res = await axios.get(`${API_BASE_URL}/admin/users`, {
            headers: { Authorization: `Bearer ${token}` }
        });
        return res.data;
    }

    // Cập nhật quyền (Role)
    async updateUserRole(userId, roleId) {
        const token = localStorage.getItem("token");
        return await axios.put(`${API_BASE_URL}/admin/users/${userId}/role`, 
            { role_id: Number(roleId) },
            { headers: { Authorization: `Bearer ${token}` } }
        );
    }

    // Cập nhật trạng thái (Khóa/Mở)
    async updateUserStatus(userId, isActive) {
        const token = localStorage.getItem("token");
        return await axios.put(`${API_BASE_URL}/admin/users/${userId}/status`, 
            { is_active: isActive },
            { headers: { Authorization: `Bearer ${token}` } }
        );
    }

    // Xóa user
    async deleteUser(userId) {
        const token = localStorage.getItem("token");
        return await axios.delete(`${API_BASE_URL}/admin/users/${userId}`, {
            headers: { Authorization: `Bearer ${token}` }
        });
    }
}

export default new UserService();
